115	// MARK: - Private methods
116	private extension BluetoothManagerImpl {
117	
118	    func setupObservers() {
119	        bleStatusObserver.combineLatest(searchingObserver)
120	            .assertNoFailure()
121	            .map { $0 && $1 }
122	            .sink { [weak self] isReady in
123	                guard let self = self else { return }
124	                if isReady {
125	                    // self.centralManager.retrieveConnectedPeripherals(withServices: [CBUUID])
126	                    self.centralManager.scanForPeripherals(withServices: [Consts.radiaCodeServiceCBUUID], options: [CBCentralManagerScanOptionAllowDuplicatesKey: true])
127	                }
128	            }
129	            .store(in: &cancellable)
130	    }
131	}
