12	typealias PeripheralConnectionState = PeripheralImpl.ConnectionState
13	
14	protocol Peripheral: AnyObject {
15	    
16	    var cbPeripheral: CBPeripheral { get }
17	
18	    var bluetoothSignal: PassthroughSubject<BluetoothSignal, Never> { get }
19	
20	    var connectionState: AnyPublisher<PeripheralConnectionState, Never> { get }
21	    
22	    var peripheralState: CurrentValueSubject<PeripheralImpl.State, Never> { get }
23	
24	    func write<T: BluetoothCommand>(command: T) async throws -> BluetoothRawStorage    
25	    
26	    func cancel()
27	}
28	
29	final class PeripheralImpl: NSObject, Peripheral {
30	
31	    enum PeripheralError: Error {
32	        case characteristic
33	        case storage
34	        case bleWriteError(Error)
35	    }
36	    
37	    enum ConnectionState: Equatable {
38	        case disconnected
39	        case disconnecting
40	        case connected
41	        case connecting
42	
43	        static func from(state: CBPeripheralState) -> Self {
44	            switch state {
45	            case .disconnected: return .disconnected
46	            case .disconnecting: return .disconnecting
47	            case .connected: return .connected
48	            case .connecting: return .connecting
49	            @unknown default: return .disconnected
50	            }
51	        }
52	    }
53	
54	    enum State {
55	        case started
56	        case ready
57	    }
58	
59	    private var service: CBService?
60	
61	    private var characteristicWrite: CBCharacteristic?
62	    private var characteristicNotify: CBCharacteristic?
63	
64	    let peripheralState = CurrentValueSubject<State, Never>(.started)
65	    let bluetoothSignal: PassthroughSubject<BluetoothSignal, Never> = .init()
66	    
67	    private var bluetoothContinuation: CheckedContinuation<BluetoothRawStorage, Error>?
68	    
69	    private var bluetoothRawStorage: BluetoothRawStorage?
70	    private var commandPackage: [Data] = [] {
71	        didSet {
72	            guard let characteristicWrite else {
73	                finishContinuationWithError(error: PeripheralError.characteristic)
74	                return
75	            }
76	            if let pack = commandPackage.first {
77	                cbPeripheral.writeValue(pack, for: characteristicWrite, type: .withResponse)
78	            }
79	        }
80	    }
81	    
82	    var connectionState: AnyPublisher<ConnectionState, Never> {
83	        cbPeripheral.publisher(for: \.state)
84	            .map { ConnectionState.from(state: $0) }
85	            .eraseToAnyPublisher()
86	    }
87	
88	    let cbPeripheral: CBPeripheral
89	
90	    init(cbPeripheral: CBPeripheral) {
91	        self.cbPeripheral = cbPeripheral
92	        super.init()
93	        self.cbPeripheral.delegate = self
94	    }
95	    
96	    func write<T: BluetoothCommand>(command: T) async throws -> BluetoothRawStorage {
97	        try await withCheckedThrowingContinuation { continuation in
98	            bluetoothRawStorage = command.storageType.instance
99	            bluetoothContinuation = continuation
100	            commandPackage = command.requestPackage()
101	        }
102	    }
103	    
104	    func cancel() {
105	        finishContinuationWithError(error: CancellationError())
106	    }
107	}
108	
109	// MARK: - CBPeripheralDelegate
110	
111	extension PeripheralImpl: CBPeripheralDelegate {
112	
113	    func peripheral(
114	        _ peripheral: CBPeripheral,
115	        didDiscoverCharacteristicsFor
116	        service: CBService,
117	        error: Error?
118	    ) {
119	        guard let characteristics = service.characteristics else {
120	            return
121	        }
122	
123	        for characteristic in characteristics {
124	            if characteristic.properties.contains(.write) {
125	                self.characteristicWrite = characteristic
126	            }
127	
128	            if characteristic.properties.contains(.notify) {
129	                peripheral.setNotifyValue(true, for: characteristic)
130	                characteristicNotify = characteristic
131	            }
132	
133	            peripheral.discoverDescriptors(for: characteristic)
134	        }
135	
136	        if characteristicWrite != nil {
137	            peripheralState.send(.ready)
138	        }
139	    }
140	
141	    func peripheral(_ peripheral: CBPeripheral, didDiscoverServices error: Error?) {
142	        guard let services = peripheral.services else { return }
143	
144	        for service in services {
145	            self.service = service
146	            peripheral.discoverCharacteristics(nil, for: service)
147	        }
148	    }
149	
150	    func peripheral(_ peripheral: CBPeripheral, didReadRSSI RSSI: NSNumber, error: Error?) {
151	        bluetoothSignal.send(.init(doubleValue: RSSI.doubleValue))
152	        Task {
153	            try await Task.sleep(seconds: 4)
154	            self.cbPeripheral.readRSSI()
155	        }
156	    }
157	
158	    func peripheral(_ peripheral: CBPeripheral, didUpdateValueFor characteristic: CBCharacteristic, error: Error?) {
159	        guard let data = characteristic.value else {
160	            finishContinuationWithError(error: CoreBluetooth.CBError(.unknown))
161	            return
162	        }
163	        
164	        guard let bluetoothRawStorage else {
165	            finishContinuationWithError(error: PeripheralError.storage)
166	            return
167	        }
168	        
169	        let bytes = data.asCollection
170	        bluetoothRawStorage.append(bytes: bytes)
171	        
172	        if bluetoothRawStorage.isLastPackage {
173	            if let continuation = bluetoothContinuation {
174	                bluetoothContinuation = nil
175	                continuation.resume(returning: bluetoothRawStorage)
176	            }
177	        }
178	    }
179	    
180	    func peripheral(_ peripheral: CBPeripheral, didWriteValueFor characteristic: CBCharacteristic, error: Error?) {
181	        if let error {
182	            finishContinuationWithError(error: PeripheralError.bleWriteError(error))
183	            return
184	        }
